'use client';

import * as React from 'react';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import IconButton from '@mui/material/IconButton';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import MenuRoundedIcon from '@mui/icons-material/MenuRounded';
import DashboardRoundedIcon from '@mui/icons-material/DashboardRounded';

export interface HeaderProps {
  title?: string;
  /**
   * เรียกตอนกดปุ่มเมนู (ไว้เปิด Drawer มือถือ)
   */
  onMenuClick?: () => void;
  /**
   * ซ่อนบน Desktop หรือไม่ (ค่าเริ่มต้น: true = แสดงเฉพาะ xs/sm)
   */
  hideOnDesktop?: boolean;
  /**
   * ใส่ปุ่ม/ตัวเลือกด้านขวา
   */
  rightSlot?: React.ReactNode;
}

export default function Header({
  title = 'Dashboard',
  onMenuClick,
  hideOnDesktop = true,
  rightSlot,
}: HeaderProps) {
  return (
    <AppBar
      position="fixed"
      elevation={0}
      sx={{
        display: hideOnDesktop ? { xs: 'block', md: 'none' } : 'block',
        bgcolor: 'background.paper',
        color: 'text.primary',
        borderBottom: '1px solid',
        borderColor: 'divider',
      }}
    >
      <Toolbar sx={{ gap: 1 }}>
        {onMenuClick && (
          <IconButton edge="start" onClick={onMenuClick} aria-label="menu">
            <MenuRoundedIcon />
          </IconButton>
        )}

        <Box
          sx={{
            width: 28,
            height: 28,
            display: 'grid',
            placeItems: 'center',
            borderRadius: '999px',
            border: '1px solid',
            borderColor: 'primary.main',
            color: 'primary.contrastText',
            background:
              'linear-gradient(135deg, hsl(210 98% 60%) 0%, hsl(210 100% 35%) 100%)',
            mr: 1,
          }}
        >
          <DashboardRoundedIcon sx={{ fontSize: 16 }} />
        </Box>

        <Typography variant="h6" sx={{ fontWeight: 700 }}>
          {title}
        </Typography>

        <Box sx={{ ml: 'auto' }}>{rightSlot}</Box>
      </Toolbar>
    </AppBar>
  );
}
